```

---

## 3. Step-by-Step Implementation

### Phase 1: Project Scaffolding

**Step 1.1 -- Initialize Next.js project**

Run inside the project directory:
```bash
npx create-next-app@latest . --typescript --tailwind --eslint --app --src-dir --import-alias "@/*"
```

This generates the standard Next.js skeleton with App Router, TypeScript, Tailwind CSS v4, and the `src/` directory layout. The `--import-alias "@/*"` sets up path aliases in `tsconfig.json`.

**Step 1.2 -- Install all dependencies**

Production dependencies:
```bash
npm install next-sanity @sanity/image-url sanity @sanity/vision \
  @stripe/stripe-js @stripe/react-stripe-js stripe \
  thirdweb \
  @portabletext/react
```

Dev dependencies (most come from create-next-app, but add):
```bash
npm install -D @types/node
```

Package rationale:
- `next-sanity` -- Sanity client for Next.js, `createClient`, `defineQuery`, `NextStudio`
- `sanity` + `@sanity/vision` -- Sanity Studio itself (embedded at `/studio`) and the GROQ query testing plugin
- `@sanity/image-url` -- Generates image URLs from Sanity image assets
- `@stripe/stripe-js` -- Client-side Stripe.js loader (`loadStripe`)
- `@stripe/react-stripe-js` -- React components: `Elements`, `PaymentElement`, `ExpressCheckoutElement`
- `stripe` -- Server-side Stripe SDK (used in the API route to create PaymentIntents)
- `thirdweb` -- v5 SDK; imports from `thirdweb/react`, `thirdweb/wallets`, `thirdweb` (replaces the old `@thirdweb-dev/react` and `@thirdweb-dev/sdk`)
- `@portabletext/react` -- Renders Sanity Portable Text (rich text body content)

**Step 1.3 -- Create `.env.local.example`**

```
# Sanity
NEXT_PUBLIC_SANITY_PROJECT_ID=
NEXT_PUBLIC_SANITY_DATASET=production
SANITY_API_READ_TOKEN=

# Stripe
NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY=
STRIPE_SECRET_KEY=

# ThirdWeb
NEXT_PUBLIC_THIRDWEB_CLIENT_ID=
```

**Step 1.4 -- Configure fonts and global styles in `src/app/globals.css`**

Use `@font-face` to load Futura (self-hosted woff2 files in `public/fonts/`) with a fallback to `"Century Gothic", "Trebuchet MS", Arial, sans-serif`. Define Helvetica as the body font stack: `"Helvetica Neue", Helvetica, Arial, sans-serif`. Set up Tailwind CSS directives and custom CSS variables for brand colors.

In `tailwind.config.ts`, extend `fontFamily`:
```ts
fontFamily: {
  title: ['"Futura"', '"Century Gothic"', 'sans-serif'],
  body: ['"Helvetica Neue"', 'Helvetica', 'Arial', 'sans-serif'],
}
```

---

### Phase 2: Sanity CMS Configuration

**Step 2.1 -- Environment helper: `sanity/env.ts`**

Export `projectId`, `dataset`, and `apiVersion` with fallbacks:
```ts
export const projectId = process.env.NEXT_PUBLIC_SANITY_PROJECT_ID || 'placeholder';
export const dataset = process.env.NEXT_PUBLIC_SANITY_DATASET || 'production';
export const apiVersion = '2024-12-01';
```

The `'placeholder'` string is intentional -- the Sanity client will fail gracefully when queries are attempted, and the demo page does not depend on live Sanity data.

**Step 2.2 -- Sanity client: `sanity/lib/client.ts`**

```ts
import { createClient } from 'next-sanity';
import { projectId, dataset, apiVersion } from '../env';

export const client = createClient({
  projectId,
  dataset,
  apiVersion,
  useCdn: true,
});
```

**Step 2.3 -- Image URL helper: `sanity/lib/image.ts`**

```ts
import imageUrlBuilder from '@sanity/image-url';
import { client } from './client';

const builder = imageUrlBuilder(client);
export function urlFor(source: any) {
  return builder.image(source);
}
```

**Step 2.4 -- Schemas: `sanity/schemas/author.ts`**

```ts
import { defineType, defineField } from 'sanity';

export const authorType = defineType({
  name: 'author',
  title: 'Author',
  type: 'document',
  fields: [
    defineField({ name: 'name', type: 'string', validation: (r) => r.required() }),
    defineField({ name: 'slug', type: 'slug', options: { source: 'name' }, validation: (r) => r.required() }),
    defineField({ name: 'avatar', type: 'image', options: { hotspot: true } }),
    defineField({ name: 'bio', type: 'text' }),
  ],
});
```

**Step 2.5 -- Schemas: `sanity/schemas/post.ts`**

```ts
import { defineType, defineField } from 'sanity';

export const postType = defineType({
  name: 'post',
  title: 'Post',
  type: 'document',
  fields: [
    defineField({ name: 'title', type: 'string', validation: (r) => r.required() }),
    defineField({ name: 'slug', type: 'slug', options: { source: 'title' }, validation: (r) => r.required() }),
    defineField({ name: 'excerpt', type: 'text', rows: 3 }),
    defineField({ name: 'featuredImage', type: 'image', options: { hotspot: true } }),
    defineField({ name: 'author', type: 'reference', to: [{ type: 'author' }] }),
    defineField({ name: 'publishedAt', type: 'datetime' }),
    defineField({
      name: 'isPremium',
      title: 'Premium Content',
      type: 'boolean',
      description: 'Toggle to enable paywall for this post',
      initialValue: false,
    }),
    defineField({
      name: 'body',
      type: 'array',
      of: [{ type: 'block' }, { type: 'image', options: { hotspot: true } }],
    }),
  ],
  preview: {
    select: { title: 'title', subtitle: 'author.name', media: 'featuredImage' },
  },
});
```

The `isPremium` boolean is the paywall toggle. When true, the frontend renders the `PaywallOverlay` on top of the article.

**Step 2.6 -- Schema index: `sanity/schemas/index.ts`**

```ts
import { postType } from './post';
import { authorType } from './author';
export const schemaTypes = [postType, authorType];
```

**Step 2.7 -- Sanity Studio config: `sanity.config.ts` (project root)**

```ts
import { defineConfig } from 'sanity';
import { structureTool } from 'sanity/structure';
import { visionTool } from '@sanity/vision';
import { schemaTypes } from './sanity/schemas';
import { projectId, dataset, apiVersion } from './sanity/env';

export default defineConfig({
  name: 'default',
  title: 'Paywalled Blog',
  projectId,
  dataset,
  apiVersion,
  basePath: '/studio',
  plugins: [structureTool(), visionTool()],
  schema: { types: schemaTypes },
});
```

**Step 2.8 -- Embedded Studio route: `src/app/studio/[[...tool]]/page.tsx`**

```tsx
'use client';
import { NextStudio } from 'next-sanity/studio';
import config from '../../../../sanity.config';

export default function StudioPage() {
  return <NextStudio config={config} />;
}
```

This is a catch-all route so all Sanity Studio sub-routes (desk, vision, etc.) work. Mark it `'use client'` because the Studio is a client-side app.

**Step 2.9 -- GROQ queries: `sanity/lib/queries.ts`**

```ts
import { defineQuery } from 'next-sanity';

export const POSTS_QUERY = defineQuery(
  `*[_type == "post" && defined(slug.current)] | order(publishedAt desc)[0...12]{
    _id, title, slug, excerpt, featuredImage, publishedAt, isPremium,
    author->{ name, slug, avatar }
  }`
);

export const POST_BY_SLUG_QUERY = defineQuery(
  `*[_type == "post" && slug.current == $slug][0]{
    _id, title, slug, excerpt, featuredImage, publishedAt, isPremium, body,
    author->{ name, slug, avatar, bio }
  }`
);
```

---

### Phase 3: Stripe Integration

**Step 3.1 -- Stripe client singleton: `src/app/lib/stripe.ts`**

```ts
import { loadStripe, Stripe } from '@stripe/stripe-js';

let stripePromise: Promise<Stripe | null> | null = null;

export const getStripe = () => {
  const key = process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY;
  if (!key) return null;  // graceful fallback
  if (!stripePromise) {
    stripePromise = loadStripe(key);
  }
  return stripePromise;
};

export const isStripeConfigured = (): boolean =>
  !!process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY;
```

**Step 3.2 -- Server API route: `src/app/api/stripe/create-payment-intent/route.ts`**

```ts
import { NextResponse } from 'next/server';
import Stripe from 'stripe';

export async function POST(request: Request) {
  const secretKey = process.env.STRIPE_SECRET_KEY;
  if (!secretKey) {
    return NextResponse.json(
      { error: 'Stripe is not configured' },
      { status: 503 }
    );
  }

  const stripe = new Stripe(secretKey, { apiVersion: '2024-12-18.acacia' });

  try {
    const { amount = 999 } = await request.json();

    const paymentIntent = await stripe.paymentIntents.create({
      amount,
      currency: 'usd',
      automatic_payment_methods: { enabled: true },
    });

    return NextResponse.json({ clientSecret: paymentIntent.client_secret });
  } catch (err: any) {
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}
```

The `automatic_payment_methods: { enabled: true }` is critical -- this lets Stripe dynamically show Apple Pay, Google Pay, Link, and card payments based on the customer's device capabilities.

**Step 3.3 -- StripeProvider: `src/app/components/providers/StripeProvider.tsx`**

A client component that wraps children in `<Elements>`. It fetches a `clientSecret` from the API route on mount. If Stripe is not configured, it renders children without the provider (fallback to mock UI).

```tsx
'use client';
import { useState, useEffect, ReactNode } from 'react';
import { Elements } from '@stripe/react-stripe-js';
import { getStripe, isStripeConfigured } from '@/app/lib/stripe';
import type { Appearance } from '@stripe/stripe-js';

const appearance: Appearance = {
  theme: 'flat',
  variables: {
    fontFamily: '"Helvetica Neue", Helvetica, Arial, sans-serif',
    colorPrimary: '#0a2540',
  },
};

export function StripeProvider({ children }: { children: ReactNode }) {
  const [clientSecret, setClientSecret] = useState<string | null>(null);
  const stripePromise = getStripe();

  useEffect(() => {
    if (!isStripeConfigured()) return;
    fetch('/api/stripe/create-payment-intent', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ amount: 999 }),
    })
      .then((res) => res.json())
      .then((data) => setClientSecret(data.clientSecret))
      .catch(console.error);
  }, []);

  if (!stripePromise || !clientSecret) {
    return <>{children}</>;  // renders mock UI
  }

  return (
    <Elements stripe={stripePromise} options={{ clientSecret, appearance }}>
      {children}
    </Elements>
  );
}
```

**Step 3.4 -- StripeCheckout component: `src/app/components/paywall/StripeCheckout.tsx`**

A client component that renders both `<PaymentElement>` (card form) and `<ExpressCheckoutElement>` (Apple Pay / Google Pay buttons) inside the paywall overlay. It uses `useStripe()` and `useElements()` hooks, and calls `stripe.confirmPayment()` on form submit.

**Step 3.5 -- MockStripeCheckout: `src/app/components/paywall/MockStripeCheckout.tsx`**

A purely visual component that renders a static card-form-looking UI and fake Apple Pay / Google Pay buttons. This is displayed when `isStripeConfigured()` returns false, ensuring the demo page always looks complete. Use Tailwind to style it identically to a real Stripe form. The Apple Pay button uses the standard black rounded-rect style; the Google Pay button uses the standard white rounded-rect with the "G" logo.

---

### Phase 4: ThirdWeb Integration

**Step 4.1 -- ThirdWeb client: `src/app/lib/thirdweb.ts`**

```ts
import { createThirdwebClient } from 'thirdweb';

const clientId = process.env.NEXT_PUBLIC_THIRDWEB_CLIENT_ID;

export const thirdwebClient = clientId
  ? createThirdwebClient({ clientId })
  : null;

export const isThirdWebConfigured = (): boolean => !!clientId;
```

**Step 4.2 -- ThirdWebProvider: `src/app/components/providers/ThirdWebProvider.tsx`**

```tsx
'use client';
import { ThirdwebProvider } from 'thirdweb/react';
import { ReactNode } from 'react';
import { isThirdWebConfigured } from '@/app/lib/thirdweb';

export function ThirdWebProviderWrapper({ children }: { children: ReactNode }) {
  if (!isThirdWebConfigured()) return <>{children}</>;
  return <ThirdwebProvider>{children}</ThirdwebProvider>;
}
```

**Step 4.3 -- ThirdWebAuth component: `src/app/components/auth/ThirdWebAuth.tsx`**

When configured, renders the real ThirdWeb `ConnectButton` with in-app wallet supporting social login:

```tsx
'use client';
import { ConnectButton } from 'thirdweb/react';
import { inAppWallet } from 'thirdweb/wallets';
import { thirdwebClient, isThirdWebConfigured } from '@/app/lib/thirdweb';
import { MockThirdWebAuth } from './MockThirdWebAuth';

const wallets = [
  inAppWallet({
    auth: { options: ['google', 'apple', 'facebook', 'email'] },
  }),
];

export function ThirdWebAuth() {
  if (!isThirdWebConfigured() || !thirdwebClient) {
    return <MockThirdWebAuth />;
  }
  return (
    <ConnectButton
      client={thirdwebClient}
      wallets={wallets}
      connectButton={{ label: 'Sign in with Social' }}
    />
  );
}
```

**Step 4.4 -- MockThirdWebAuth: `src/app/components/auth/MockThirdWebAuth.tsx`**

A styled button that visually mimics the ConnectButton. On click, it shows a toast or small modal saying "ThirdWeb not configured -- set NEXT_PUBLIC_THIRDWEB_CLIENT_ID". Uses the same font styling and dimensions as the real component.

---

### Phase 5: Paywall Overlay

This is the centerpiece UI -- a full-viewport overlay that sits on top of blurred article content, replicating the NYT/Washington Post paywall experience.

**Step 5.1 -- PaywallOverlay: `src/app/components/paywall/PaywallOverlay.tsx`**

Architecture:
- The article content is rendered normally behind the overlay.
- A CSS gradient fade (white-to-transparent going upward) covers the bottom 60% of the article.
- On top of that, a fixed/absolute-positioned overlay with `backdrop-filter: blur(6px)` and a semi-transparent background.
- Inside the overlay: a centered card containing the payment/auth UI.

```tsx
'use client';
import { useState } from 'react';
import { StripeCheckout } from './StripeCheckout';
import { MockStripeCheckout } from './MockStripeCheckout';
import { ThirdWebAuth } from '../auth/ThirdWebAuth';
import { isStripeConfigured } from '@/app/lib/stripe';

export function PaywallOverlay() {
  const [dismissed, setDismissed] = useState(false);

  if (dismissed) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center">
      {/* Background blur + fade */}
      <div className="absolute inset-0 bg-gradient-to-t from-white via-white/95 to-transparent" />
      <div className="absolute inset-0 backdrop-blur-sm" />

      {/* Paywall card */}
      <div className="relative z-10 w-full max-w-lg mx-auto mb-12 bg-white rounded-2xl shadow-2xl p-8 border border-gray-200">
        <h2 className="font-title text-2xl font-bold text-center mb-2">
          Subscribe to continue reading
        </h2>
        <p className="font-body text-gray-600 text-center mb-6">
          Get unlimited access to premium articles for $9.99/month
        </p>

        {/* ThirdWeb social sign-in */}
        <div className="mb-6">
          <p className="text-sm text-gray-500 text-center mb-3">
            Already a member? Sign in
          </p>
          <div className="flex justify-center">
            <ThirdWebAuth />
          </div>
        </div>

        <div className="border-t border-gray-200 my-6" />

        {/* Stripe payment */}
        {isStripeConfigured() ? <StripeCheckout /> : <MockStripeCheckout />}
      </div>
    </div>
  );
}
```

Key styling decisions:
- `font-title` class uses Futura (configured in Tailwind).
- `font-body` class uses Helvetica.
- The gradient goes from fully opaque white at the bottom to transparent at the top, so the article text fades out naturally.
- The card is `max-w-lg`, centered, with rounded corners and shadow -- matching modern paywall aesthetics.

---

### Phase 6: Blog Components

**Step 6.1 -- BlogPost: `src/app/components/blog/BlogPost.tsx`**

Renders a full blog post: title (Futura), author badge, published date, featured image, and body content (via `@portabletext/react`). Accepts a `isPremium` prop; when true, the component co-renders the `PaywallOverlay`.

Layout pattern:
```tsx
<article className="relative">
  <header>
    <h1 className="font-title text-4xl font-bold">{title}</h1>
    <AuthorBadge author={author} date={publishedAt} />
    {featuredImage && <img ... />}
  </header>
  <div className={isPremium ? 'max-h-[600px] overflow-hidden' : ''}>
    <PortableText value={body} />
  </div>
  {isPremium && <PaywallOverlay />}
</article>
```

The `max-h-[600px] overflow-hidden` truncates the article body so only the first portion is visible, reinforcing the paywall effect.

**Step 6.2 -- BlogPostCard: `src/app/components/blog/BlogPostCard.tsx`**

A card component for the listing page. Shows featured image, title, excerpt, author, and a "Premium" badge when `isPremium` is true.

**Step 6.3 -- AuthorBadge: `src/app/components/blog/AuthorBadge.tsx`**

Small component: author avatar (circular), name, and formatted date.

---

### Phase 7: The Demo Page

**Step 7.1 -- Constants file: `src/app/lib/constants.ts`**

Contains hardcoded demo content so the `/demo` page works without any external services:

```ts
export const DEMO_POST = {
  title: 'The Future of Decentralized Media',
  author: { name: 'Jane Nakamoto', avatar: null },
  publishedAt: '2025-01-15T10:00:00Z',
  isPremium: true,
  excerpt: 'How blockchain technology is reshaping content monetization...',
  body: [
    // 6-8 paragraphs of placeholder text (NOT lorem ipsum -- actual
    // readable placeholder about decentralized media, Web3, creator
    // economies, etc.)
  ],
};
```

**Step 7.2 -- Demo page: `src/app/demo/page.tsx`**

This is a self-contained page that renders the full paywall experience using hardcoded data. It does NOT depend on Sanity, Stripe, or ThirdWeb being configured. It imports mock components as fallbacks.

```tsx
import { DEMO_POST } from '@/app/lib/constants';
import { BlogPost } from '@/app/components/blog/BlogPost';
import { ThirdWebProviderWrapper } from '@/app/components/providers/ThirdWebProvider';
import { StripeProvider } from '@/app/components/providers/StripeProvider';

export const metadata = {
  title: 'Paywall Demo',
  description: 'Interactive demo of the paywalled blog experience',
};

export default function DemoPage() {
  return (
    <ThirdWebProviderWrapper>
      <StripeProvider>
        <main className="min-h-screen bg-white">
          <div className="max-w-3xl mx-auto px-4 py-12">
            <BlogPost
              title={DEMO_POST.title}
              author={DEMO_POST.author}
              publishedAt={DEMO_POST.publishedAt}
              isPremium={DEMO_POST.isPremium}
              body={DEMO_POST.body}
              excerpt={DEMO_POST.excerpt}
              featuredImage={null}
            />
          </div>
        </main>
      </StripeProvider>
    </ThirdWebProviderWrapper>
  );
}
```

The provider wrappers detect missing env vars and pass through without wrapping, so the mock UI components render in their place. The page is always visually complete.

---

### Phase 8: Dynamic Blog Pages (Sanity-powered)

**Step 8.1 -- Home page: `src/app/page.tsx`**

An async Server Component that fetches posts from Sanity using `POSTS_QUERY`. Wraps the fetch in a try/catch; on failure (Sanity not configured), falls back to showing the demo post card with a link to `/demo`.

**Step 8.2 -- Post detail page: `src/app/(blog)/posts/[slug]/page.tsx`**

An async Server Component that fetches a single post by slug using `POST_BY_SLUG_QUERY`. If the post has `isPremium: true`, it wraps the page in the providers and renders `BlogPost` with the `PaywallOverlay`. If Sanity fetch fails, redirects to `/demo`.

---

### Phase 9: Root Layout and Providers

**Step 9.1 -- Root layout: `src/app/layout.tsx`**

```tsx
import type { Metadata } from 'next';
import './globals.css';

export const metadata: Metadata = {
  title: 'Paywalled Blog',
  description: 'A demo paywalled blog with Sanity CMS, Stripe, and ThirdWeb',
};

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <body className="font-body antialiased text-gray-900">
        <header className="border-b border-gray-200 py-4 px-6">
          <nav className="max-w-5xl mx-auto flex items-center justify-between">
            <a href="/" className="font-title text-xl font-bold">
              The Paywall Times
            </a>
            <div className="flex items-center gap-4">
              <a href="/demo" className="text-sm text-gray-600 hover:text-black">
                Demo
              </a>
              <a href="/studio" className="text-sm text-gray-600 hover:text-black">
                Studio
              </a>
            </div>
