export const SUBSCRIPTION_PRICE = "$9.99/month";
export const SITE_NAME = "The Paywall Times";

export const apiVersion =
  process.env.NEXT_PUBLIC_SANITY_API_VERSION || "2024-01-01";

export const dataset =
  process.env.NEXT_PUBLIC_SANITY_DATASET || "production";

export const projectId =
  process.env.NEXT_PUBLIC_SANITY_PROJECT_ID || "";

export const useCdn = false;

import { createClient } from "next-sanity";
import { apiVersion, dataset, projectId, useCdn } from "../env";

export const client = projectId
  ? createClient({ apiVersion, dataset, projectId, useCdn })
  : null;

import { client } from "./client";
import { Post } from "@/../../types";

const POSTS_QUERY = `*[_type == "post"] | order(publishedAt desc) {
  _id,
  title,
  slug,
  excerpt,
  featuredImage,
  "author": author->{_id, name, slug, avatar, bio},
  publishedAt,
  isPremium,
  body
}`;

const POST_BY_SLUG_QUERY = `*[_type == "post" && slug.current == $slug][0] {
  _id,
  title,
  slug,
  excerpt,
  featuredImage,
  "author": author->{_id, name, slug, avatar, bio},
  publishedAt,
  isPremium,
  body
}`;

export async function getPosts(): Promise<Post[]> {
  if (!client) return [];
  return client.fetch(POSTS_QUERY);
}

export async function getPostBySlug(slug: string): Promise<Post | null> {
  if (!client) return null;
  return client.fetch(POST_BY_SLUG_QUERY, { slug });
}

import imageUrlBuilder from "@sanity/image-url";
import { client } from "./client";

const builder = client ? imageUrlBuilder(client) : null;

export function urlFor(source: { asset: { _ref: string } }) {
  if (!builder) return null;
  return builder.image(source);
}

