"use client";

import { useState, useEffect, ReactNode } from "react";
import { Elements } from "@stripe/react-stripe-js";
import { getStripe } from "@/app/lib/stripe";
import type { Stripe, StripeElementsOptions } from "@stripe/stripe-js";

interface StripeProviderProps {
  children: ReactNode;
}

export default function StripeProvider({ children }: StripeProviderProps) {
  const [stripe, setStripe] = useState<Stripe | null>(null);
  const [clientSecret, setClientSecret] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const stripePromise = getStripe();
    if (!stripePromise) return;

    stripePromise.then(setStripe);

    fetch("/api/stripe/create-payment-intent", { method: "POST" })
      .then((res) => res.json())
      .then((data) => {
        if (data.clientSecret) {
          setClientSecret(data.clientSecret);
        } else {
          setError(data.error || "Failed to create payment intent");
        }
      })
      .catch(() => setError("Failed to connect to payment server"));
  }, []);

  if (error || !stripe || !clientSecret) {
    return <>{children}</>;
  }

  const options: StripeElementsOptions = {
    clientSecret,
    appearance: {
      theme: "stripe",
      variables: {
        colorPrimary: "#4f46e5",
        borderRadius: "8px",
      },
    },
  };

  return (
    <Elements stripe={stripe} options={options}>
      {children}
    </Elements>
  );
}

"use client";

import {
  PaymentElement,
  ExpressCheckoutElement,
  useStripe,
  useElements,
} from "@stripe/react-stripe-js";
import { useState } from "react";

export default function StripeCheckout() {
  const stripe = useStripe();
  const elements = useElements();
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!stripe || !elements) return;

    setLoading(true);
    const { error } = await stripe.confirmPayment({
      elements,
      confirmParams: {
        return_url: `${window.location.origin}/demo?success=true`,
      },
    });

    if (error) {
      setMessage(error.message || "Payment failed");
    }
    setLoading(false);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-3">
      <ExpressCheckoutElement
        onConfirm={async () => {
          if (!stripe || !elements) return;
          await stripe.confirmPayment({
            elements,
            confirmParams: {
              return_url: `${window.location.origin}/demo?success=true`,
            },
          });
        }}
      />
      <div className="flex items-center gap-3 my-3">
        <div className="flex-1 h-px bg-gray-200" />
        <span className="text-xs text-gray-400 uppercase tracking-wide">
          Or pay with card
        </span>
        <div className="flex-1 h-px bg-gray-200" />
      </div>
      <PaymentElement />
      <button
        type="submit"
        disabled={!stripe || loading}
        className="w-full bg-indigo-600 text-white rounded-md py-2.5 text-sm font-semibold hover:bg-indigo-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
      >
        {loading ? "Processing..." : "Subscribe — $9.99/mo"}
      </button>
      {message && (
        <p className="text-sm text-red-500 text-center">{message}</p>
      )}
    </form>
  );
}

