  _id,
  title,
  slug,
  excerpt,
  featuredImage,
  "author": author->{_id, name, slug, avatar, bio},
  publishedAt,
  isPremium,
  body
}`;

export async function getPosts(): Promise<Post[]> {
  if (!client) return [];
  return client.fetch(POSTS_QUERY);
}

